import{_ as e}from"./chunks/ue-plugin-enabled.Ln1oOl8v.js";import{_ as o}from"./chunks/settings-add-model.Cxj4wiLe.js";import{_ as a,o as d,c as r,ag as i}from"./chunks/framework.BqfgOMAh.js";const x=JSON.parse('{"title":"安装步骤","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/installation.md","filePath":"zh/guide/installation.md"}'),l={name:"zh/guide/installation.md"};function s(n,t,h,c,u,g){return d(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h1><p>NexusFlow 由两部分组成，需要分别安装：</p><ul><li><strong>NexusFlow 主程序</strong>（免费）— 提供 AI 对话界面的桌面应用，从 GitHub 下载</li><li><strong>NexusFlow UE 插件</strong> — 安装在 UE 编辑器中的配套插件，从 Fab.com 获取</li></ul><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>最低要求</th></tr></thead><tbody><tr><td>操作系统</td><td>Windows 10 / 11 (64-bit)</td></tr><tr><td>虚幻引擎</td><td>Unreal Engine 5.6 或 5.7</td></tr><tr><td>LLM API Key</td><td>支持 OpenAI / Anthropic / Google Gemini / DeepSeek / 智谱 GLM / MiniMax / 通义千问 / Kimi</td></tr><tr><td>网络</td><td>需要网络连接以调用 AI 模型 API</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">UE 版本兼容性</p><p>NexusFlow 仅支持 <strong>UE 5.6</strong> 和 <strong>UE 5.7</strong>。UE 5.5 及更早版本因 ONNX Runtime 版本不兼容而不受支持。</p></div><h2 id="安装主程序-来自-github" tabindex="-1">安装主程序（来自 GitHub） <a class="header-anchor" href="#安装主程序-来自-github" aria-label="Permalink to &quot;安装主程序（来自 GitHub）&quot;">​</a></h2><p>NexusFlow 主程序是免费的桌面应用，负责提供 AI 对话界面和 LLM API 代理。</p><h3 id="下载" tabindex="-1">下载 <a class="header-anchor" href="#下载" aria-label="Permalink to &quot;下载&quot;">​</a></h3><p>前往 <a href="https://github.com/maxzhao/NexusFlow/releases" target="_blank" rel="noreferrer">GitHub Releases</a> 页面，下载最新版本的安装包（<code>.exe</code>）。</p><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h3><ol><li>双击下载的 <code>.exe</code> 安装程序（NSIS 安装器）</li><li>选择安装语言（简体中文 / English）</li><li>按照安装向导提示选择安装目录</li><li>完成安装</li></ol><div class="tip custom-block"><p class="custom-block-title">安装模式</p><p>安装器支持「仅为当前用户安装」和「为所有用户安装」两种模式。</p></div><h3 id="首次启动" tabindex="-1">首次启动 <a class="header-anchor" href="#首次启动" aria-label="Permalink to &quot;首次启动&quot;">​</a></h3><p>安装完成后启动 NexusFlow：</p><ol><li>桌面上出现一个悬浮球图标（蓝紫色渐变圆球）</li><li>点击悬浮球，首次会自动进入 <a href="./getting-started#首次运行向导">引导向导</a></li><li>向导会引导你配置 AI 模型和检查 UE 插件状态</li></ol><h2 id="安装-ue-插件-来自-fab" tabindex="-1">安装 UE 插件（来自 Fab） <a class="header-anchor" href="#安装-ue-插件-来自-fab" aria-label="Permalink to &quot;安装 UE 插件（来自 Fab）&quot;">​</a></h2><p>NexusFlow 需要在 UE 编辑器中安装配套插件，才能实现与编辑器的通信。</p><h3 id="从-fab-安装-推荐" tabindex="-1">从 Fab 安装（推荐） <a class="header-anchor" href="#从-fab-安装-推荐" aria-label="Permalink to &quot;从 Fab 安装（推荐）&quot;">​</a></h3><ol><li>前往 <a href="https://www.fab.com/" target="_blank" rel="noreferrer">Fab.com</a> 搜索 <strong>NexusFlow</strong></li><li>购买并将插件安装到你的 UE 引擎（支持 UE 5.6 和 5.7）</li><li>重启 UE 编辑器</li></ol><h3 id="手动安装" tabindex="-1">手动安装 <a class="header-anchor" href="#手动安装" aria-label="Permalink to &quot;手动安装&quot;">​</a></h3><p>如果你已经有插件文件（例如从其他途径获取）：</p><ol><li>关闭 UE 编辑器</li><li>将 <code>NexusFlow</code> 插件文件夹复制到你的 UE 项目的 <code>Plugins/</code> 目录下</li><li>重新打开 UE 编辑器</li><li>前往 <strong>编辑 &gt; 插件管理器</strong>，确认 NexusFlow 插件已启用</li></ol><h3 id="验证插件安装" tabindex="-1">验证插件安装 <a class="header-anchor" href="#验证插件安装" aria-label="Permalink to &quot;验证插件安装&quot;">​</a></h3><p><img src="'+e+'" alt="UE 中 NexusFlow 插件配置页面"></p><p>你可以通过 NexusFlow 主程序的 <strong>设置 &gt; 关于</strong> 页面检查插件安装状态：</p><ul><li>✅ <strong>已检测到插件</strong> — 安装成功</li><li>❌ <strong>未检测到插件</strong> — 请检查安装步骤或重新安装</li></ul><p>点击「重新检测」按钮可以手动刷新检测结果。</p><h2 id="ue-插件首次启动" tabindex="-1">UE 插件首次启动 <a class="header-anchor" href="#ue-插件首次启动" aria-label="Permalink to &quot;UE 插件首次启动&quot;">​</a></h2><p>UE 编辑器启动并加载 NexusFlow 插件后，插件会自动检测你的环境。如果有缺失项，会弹出 <strong>NexusFlow Setup</strong> 设置对话框。</p><h3 id="检测内容" tabindex="-1">检测内容 <a class="header-anchor" href="#检测内容" aria-label="Permalink to &quot;检测内容&quot;">​</a></h3><table tabindex="0"><thead><tr><th>检测项</th><th>检测内容</th><th>检测方式</th></tr></thead><tbody><tr><td><strong>NexusFlow 桌面应用</strong></td><td>主程序是否已安装</td><td>Windows 注册表查询</td></tr><tr><td><strong>Embedding 模型</strong></td><td>RAG 搜索模型是否就绪</td><td>Bridge FFI 状态检查</td></tr></tbody></table><h3 id="弹窗时机" tabindex="-1">弹窗时机 <a class="header-anchor" href="#弹窗时机" aria-label="Permalink to &quot;弹窗时机&quot;">​</a></h3><ul><li><strong>全部就绪</strong> — 无弹窗，插件静默启动</li><li><strong>有缺失项</strong> — 启动约 2 秒后弹出设置对话框</li><li><strong>已选择&quot;不再提示&quot;</strong> — 即使有缺失也不弹窗</li></ul><h3 id="对话框选项" tabindex="-1">对话框选项 <a class="header-anchor" href="#对话框选项" aria-label="Permalink to &quot;对话框选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>效果</th></tr></thead><tbody><tr><td><strong>Download Model</strong></td><td>在后台开始下载 Embedding 模型（约 90 MB）</td></tr><tr><td><strong>Open Settings</strong></td><td>打开 <strong>项目设置 &gt; 插件 &gt; NexusFlow</strong> 进行手动配置</td></tr><tr><td><strong>Later</strong></td><td>关闭对话框，下次启动仍会提示</td></tr><tr><td><strong>Don&#39;t Show Again</strong></td><td>永久隐藏对话框（可在设置中重新启用）</td></tr></tbody></table><h3 id="未安装主程序时的下载链接" tabindex="-1">未安装主程序时的下载链接 <a class="header-anchor" href="#未安装主程序时的下载链接" aria-label="Permalink to &quot;未安装主程序时的下载链接&quot;">​</a></h3><p>如果未检测到 NexusFlow 桌面应用，对话框会提供两个下载链接：</p><ul><li><strong>GitHub</strong> — <a href="https://github.com/maxzhao/NexusFlow/releases/latest" target="_blank" rel="noreferrer">发布页面</a></li><li><strong>Mirror</strong> — 国内加速下载链接</li></ul><h3 id="重新启用设置对话框" tabindex="-1">重新启用设置对话框 <a class="header-anchor" href="#重新启用设置对话框" aria-label="Permalink to &quot;重新启用设置对话框&quot;">​</a></h3><p>如果之前选择了&quot;Don&#39;t Show Again&quot;，想重新显示对话框：</p><ol><li>找到 NexusFlow 配置文件：<code>%LOCALAPPDATA%/NexusFlow/config.json</code></li><li>将 <code>&quot;showSetupWizard&quot;</code> 设为 <code>true</code></li><li>重启 UE 编辑器</li></ol><p>也可以随时在 <strong>项目设置 &gt; 插件 &gt; NexusFlow</strong> 中查看环境状态。</p><h2 id="配置-ai-模型" tabindex="-1">配置 AI 模型 <a class="header-anchor" href="#配置-ai-模型" aria-label="Permalink to &quot;配置 AI 模型&quot;">​</a></h2><p>NexusFlow 需要至少配置一个 AI 模型才能正常使用。你可以通过以下两种方式配置：</p><h3 id="方式一-首次运行向导" tabindex="-1">方式一：首次运行向导 <a class="header-anchor" href="#方式一-首次运行向导" aria-label="Permalink to &quot;方式一：首次运行向导&quot;">​</a></h3><p>首次启动时，向导的第 2 步会引导你配置 AI 模型。详见 <a href="./getting-started#第-2-步-配置-ai-模型">快速入门</a>。</p><h3 id="方式二-设置页面" tabindex="-1">方式二：设置页面 <a class="header-anchor" href="#方式二-设置页面" aria-label="Permalink to &quot;方式二：设置页面&quot;">​</a></h3><ol><li>点击侧边栏顶部的齿轮图标，进入设置</li><li>选择 <strong>AI 模型</strong></li><li>点击「添加模型」</li><li>填写配置信息（详见下方说明）</li></ol><p><img src="'+o+'" alt="添加 AI 模型表单"></p><h3 id="支持的-ai-模型提供商" tabindex="-1">支持的 AI 模型提供商 <a class="header-anchor" href="#支持的-ai-模型提供商" aria-label="Permalink to &quot;支持的 AI 模型提供商&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Provider</th><th>模型示例</th><th>说明</th></tr></thead><tbody><tr><td><strong>OpenAI</strong></td><td><code>gpt-5.4</code>, <code>gpt-5.3-codex</code></td><td>OpenAI 官方 API</td></tr><tr><td><strong>Anthropic</strong></td><td><code>claude-opus-4-6</code>, <code>claude-sonnet-4-20250514</code></td><td>需要设置 Max Tokens</td></tr><tr><td><strong>Google Gemini</strong></td><td><code>gemini-3.1-pro-preview</code>, <code>gemini-2.5-pro</code></td><td>Google AI Studio API</td></tr><tr><td><strong>DeepSeek</strong></td><td><code>deepseek-chat</code>, <code>deepseek-reasoner</code></td><td>性价比较高的选择</td></tr><tr><td><strong>智谱 GLM</strong></td><td><code>GLM-4.7</code>, <code>GLM-5</code></td><td>模型名大小写敏感</td></tr><tr><td><strong>MiniMax</strong></td><td><code>MiniMax-M2.7</code>, <code>MiniMax-M2.7-highspeed</code></td><td>需要设置 Max Tokens</td></tr><tr><td><strong>通义千问</strong></td><td><code>qwen3-max</code>, <code>qwen3.5-plus</code></td><td>阿里云百炼 API</td></tr><tr><td><strong>Kimi</strong></td><td><code>kimi-k2.5</code>, <code>kimi-k2-turbo-preview</code></td><td>月之暗面 API</td></tr><tr><td><strong>Custom</strong></td><td>自定义模型</td><td>支持任何兼容以上协议的 API</td></tr></tbody></table><h3 id="配置字段说明" tabindex="-1">配置字段说明 <a class="header-anchor" href="#配置字段说明" aria-label="Permalink to &quot;配置字段说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td>Provider</td><td>✅</td><td>选择模型提供商</td></tr><tr><td>模型名称</td><td>✅</td><td>自定义名称，显示在模型列表中</td></tr><tr><td>API Key</td><td>✅</td><td>提供商分配的 API 密钥，或 <code>${OPENAI_API_KEY}</code> 这类环境变量引用</td></tr><tr><td>模型标识</td><td>✅</td><td>模型 ID，如 <code>gpt-5.4</code></td></tr><tr><td>API 地址</td><td>Custom 时必填</td><td>自定义 API 端点 URL</td></tr><tr><td>通讯协议</td><td>Custom 时必填</td><td>OpenAI Compatible / OpenAI Responses API / Anthropic Messages API / Google Gemini API</td></tr><tr><td>Temperature</td><td>可选</td><td>生成随机性（0-2），越高越随机</td></tr><tr><td>Max Tokens</td><td>可选*</td><td>最大输出 token 数。*使用 Anthropic 协议时为必填</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">提示</p><p>你可以添加多个模型，并设置其中一个为默认模型。在模型列表中点击模型卡片可以查看详情和管理操作。</p></div><div class="warning custom-block"><p class="custom-block-title">API Key 安全</p><p>API Key 可直接填写，也可以填写 <code>${ENV_NAME}</code> 环境变量引用（例如 <code>${OPENAI_API_KEY}</code>）。直接填写的 API Key 会在界面上以掩码形式显示（<code>sk-****</code>），点击眼睛图标可切换可见性；环境变量引用会显示为变量名。真实 API Key 只存储在本地，环境变量模式下应用配置中不会保存真实密钥。</p></div><h2 id="验证安装" tabindex="-1">验证安装 <a class="header-anchor" href="#验证安装" aria-label="Permalink to &quot;验证安装&quot;">​</a></h2><p>安装完成后，进行以下检查确认一切正常：</p><ol><li><strong>启动 NexusFlow</strong> — 悬浮球出现在屏幕上</li><li><strong>点击悬浮球</strong> — 侧边栏正常打开</li><li><strong>检查模型</strong> — 设置 &gt; AI 模型 中有至少一个模型，且验证状态为通过</li><li><strong>启动 UE</strong> — 侧边栏底部状态栏显示绿色连接状态</li><li><strong>发送消息</strong> — 尝试输入「你好」确认 AI 正常回复</li></ol><p>如果遇到问题，请参考 <a href="./../faq/troubleshooting">故障排除</a>。</p>',60)])])}const A=a(l,[["render",s]]);export{x as __pageData,A as default};
